INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
-- B66: Advanced Algorithmic Mastery (50)
('ALGO_MASTER: IG Reels distribution: les 200 premieres vues sont le test. Si 15%+ interagissent (save/share/comment) → push a 2K → 20K → 200K.', 'IG Reels: 200 vues test. 15% interaction → 2K→20K→200K', 'content', 'insight', 0.90, 'algo_master', 'system'),
('ALGO_MASTER: LinkedIn post lifecycle: 1h premier push aux followers → 2-8h extension reseau 2nd degre → 8-48h viral si engagement fort → 48h+ declin.', 'LinkedIn lifecycle: 1h followers → 2-8h 2nd degre → 8-48h viral → 48h+ declin', 'content', 'insight', 0.88, 'algo_master', 'system'),
('ALGO_MASTER: TikTok batch processing: les videos sont evaluees par lots de 300-500 vues. Chaque lot positif (completion>20%) → lot suivant 10x plus grand.', 'TikTok batches: 300-500 vues/lot. Completion>20% → lot 10x', 'tiktok_comments', 'insight', 0.88, 'algo_master', 'system'),
('ALGO_MASTER: YouTube recommendation engine: 70% du watch time vient des recommandations. Optimiser le CTR miniature + retention = etre recommande.', 'YouTube: 70% watch time = recommandations. CTR + retention = etre recommande', 'content', 'insight', 0.88, 'algo_master', 'system'),
('ALGO_MASTER: Google E-E-A-T signals: author byline + author page + credentials + citations + publication history + external mentions = trust maximal.', 'EEAT signals: author + credentials + citations + publications + mentions', 'seo', 'best_practice', 0.90, 'algo_master', 'system'),
('ALGO_MASTER: Meta Ads learning phase: 50 conversions en 7 jours = sortie de la learning phase. Avant: ne pas toucher au budget ni a l audience.', 'Meta learning phase: 50 conv/7j = sortie. Avant: ne rien toucher', 'ads', 'best_practice', 0.88, 'algo_master', 'system'),
('ALGO_MASTER: Google Search ranking factors 2026 top 5: 1) contenu utile + EEAT, 2) backlinks qualite, 3) UX/Core Web Vitals, 4) search intent match, 5) freshness.', 'Google ranking 2026: contenu EEAT > backlinks > UX > intent > freshness', 'seo', 'insight', 0.90, 'algo_master', 'system'),
('ALGO_MASTER: Instagram hashtag strategy 2026: 3-5 hashtags maximum. Mix: 1 broad (1M+), 2 medium (100K-1M), 2 niche (10K-100K). Dans le caption pas les comments.', 'IG hashtags 2026: 3-5 max. 1 broad + 2 medium + 2 niche. Dans caption', 'content', 'best_practice', 0.85, 'algo_master', 'system'),
('ALGO_MASTER: Email deliverability algorithm: reputation expediteur (40%) + engagement destinataire (30%) + contenu (20%) + infrastructure (10%).', 'Email delivrabilite: reputation 40% + engagement 30% + contenu 20% + infra 10%', 'email', 'insight', 0.88, 'algo_master', 'system'),
('ALGO_MASTER: Google Maps local ranking: distance (40%) + pertinence (30%) + importance (30%). L importance = avis + citations + backlinks + anciennete.', 'GMaps ranking: distance 40% + pertinence 30% + importance 30%', 'gmaps', 'insight', 0.88, 'algo_master', 'system'),
-- B67: Elite Conversion Psychology (50)
('CONV_PSY: Le paradoxe de la confiance: montrer ses faiblesses (on n est pas parfait pour X) augmente la credibilite et la confiance de 30%.', 'Paradoxe confiance: montrer faiblesses = +30% credibilite', 'commercial', 'insight', 0.85, 'conv_psychology', 'system'),
('CONV_PSY: Le peak-end rule: les gens jugent une experience par son pic (meilleur moment) et sa fin. Finir chaque interaction sur une note positive.', 'Peak-end rule: finir chaque interaction positivement', 'commercial', 'insight', 0.85, 'conv_psychology', 'system'),
('CONV_PSY: Le processing fluency: les informations faciles a traiter sont percues comme plus vraies. Police lisible + phrases courtes + mots simples = plus de confiance.', 'Processing fluency: facile a lire = percu plus vrai. Simple = confiance', 'content', 'insight', 0.85, 'conv_psychology', 'system'),
('CONV_PSY: Le identifiable victim effect: une histoire personnelle (Marie, restauratrice a Lyon) convainc plus que des statistiques (1000 restaurants utilisent...).', 'Identifiable victim: histoire personnelle > statistiques pour convaincre', 'content', 'insight', 0.85, 'conv_psychology', 'system'),
('CONV_PSY: Le goal gradient effect: plus on s approche du but, plus on est motive. Barre de progression dans l onboarding = +40% completion.', 'Goal gradient: plus pres du but = plus motive. Progress bar = +40%', 'onboarding', 'insight', 0.85, 'conv_psychology', 'system'),
('CONV_PSY: Le labor illusion: montrer le travail fait (on a analyse 500 prospects pour vous) augmente la valeur percue de 35%.', 'Labor illusion: montrer le travail fait = +35% valeur percue', NULL, 'insight', 0.82, 'conv_psychology', 'system'),
('CONV_PSY: Le fresh start effect: les gens sont plus receptifs au changement au debut (lundi, 1er du mois, nouvelle annee). Cibler les campagnes sur ces moments.', 'Fresh start effect: lundi/1er du mois/nouvelle annee = plus receptifs', 'marketing', 'insight', 0.82, 'conv_psychology', 'system'),
('CONV_PSY: Le pratfall effect: une erreur mineure d une marque competente la rend plus humaine et attachante. +20% de sympathie.', 'Pratfall effect: erreur mineure marque competente = +20% sympathie', 'marketing', 'insight', 0.78, 'conv_psychology', 'system'),
('CONV_PSY: Le rhyme-as-reason effect: les phrases qui riment sont percues comme plus vraies (Satisfaction garantie, simplicite assuree).', 'Rhyme-as-reason: phrases qui riment = percues plus vraies', 'content', 'insight', 0.75, 'conv_psychology', 'system'),
('CONV_PSY: Le bizarreness effect: les informations etranges ou surprenantes sont memorisees 3x mieux que les informations ordinaires.', 'Bizarreness effect: etrange/surprenant = 3x mieux memorise', 'content', 'insight', 0.82, 'conv_psychology', 'system'),
-- B68: Advanced Financial Intelligence (50)
('FIN_INTEL: Le SaaS valuation multiple: ARR × multiple. Pre-revenue: 5-10x. Early: 10-20x. Growth: 15-30x. Scale: 20-40x. Depends on growth + margins.', 'SaaS valuation: ARR × multiple. Pre-rev 5-10x, early 10-20x, growth 15-30x', 'comptable', 'insight', 0.82, 'fin_intel', 'system'),
('FIN_INTEL: Le SaaS magic number: (current quarter net new ARR / previous quarter S&M spend). > 0.75 = efficient. > 1 = hyper efficient.', 'Magic number: net new ARR / prev S&M. >0.75 efficient, >1 hyper', 'comptable', 'insight', 0.82, 'fin_intel', 'system'),
('FIN_INTEL: Le burn multiple: net burn / net new ARR. < 1 = excellent. 1-2 = bon. 2-4 = acceptable. > 4 = trop de burn pour la croissance.', 'Burn multiple: burn/ARR. <1 excellent, 1-2 bon, 2-4 ok, >4 trop', 'comptable', 'insight', 0.82, 'fin_intel', 'system'),
('FIN_INTEL: Le revenue retention waterfall: beginning MRR + new + expansion - contraction - churn = ending MRR. Tracker chaque composant mensuellement.', 'Revenue waterfall: begin + new + expansion - contraction - churn = end MRR', 'comptable', 'best_practice', 0.85, 'fin_intel', 'system'),
('FIN_INTEL: Le cash conversion score: (operating cash flow / EBITDA) × 100. > 80% = excellent cash generation. < 50% = cash trapped.', 'Cash conversion: (OCF/EBITDA)×100. >80% excellent, <50% trapped', 'comptable', 'insight', 0.78, 'fin_intel', 'system'),
('FIN_INTEL: Le CAC payback chart: tracer le nombre de mois pour recuperer le CAC par cohorte. Si la courbe s allonge = probleme de unit economics.', 'CAC payback chart par cohorte: courbe allonge = probleme unit economics', 'comptable', 'best_practice', 0.82, 'fin_intel', 'system'),
('FIN_INTEL: Le gross margin optimization SaaS: serveurs (cible < 10% revenu), API IA (cible < 15%), support (cible < 5%). Total COGS < 30%.', 'Gross margin SaaS: serveurs <10%, API <15%, support <5%. COGS <30%', 'comptable', 'best_practice', 0.82, 'fin_intel', 'system'),
('FIN_INTEL: Le pricing power test: augmenter les prix de 10% pour les nouveaux clients. Si le churn rate reste stable = pricing power confirme.', 'Pricing power test: +10% nouveaux clients. Churn stable = power confirme', 'comptable', 'insight', 0.80, 'fin_intel', 'system'),
('FIN_INTEL: Le expansion revenue target: > 30% du net new MRR doit venir de l expansion (upsell + cross-sell). Le signe d un produit sticky.', 'Expansion > 30% net new MRR = produit sticky', 'comptable', 'best_practice', 0.85, 'fin_intel', 'system'),
('FIN_INTEL: Le customer concentration risk: aucun client ne doit representer > 10% du revenu. Au-dela = risque majeur si ce client churne.', 'Customer concentration: max 10% revenu par client. Au-dela = risque', 'comptable', 'best_practice', 0.85, 'fin_intel', 'system'),
-- B69: Elite Copywriting Formulas (50)
('COPY_ELITE: Le PPPP formula: Picture (peindre le resultat) → Promise (ce que vous obtenez) → Prove (preuves) → Push (CTA). Pour les landing pages.', 'PPPP: Picture + Promise + Prove + Push. Landing pages', 'content', 'best_practice', 0.85, 'copy_elite', 'system'),
('COPY_ELITE: Le APP formula: Agree (reconnaitre le probleme) → Promise (la solution) → Preview (apercu du resultat). Pour les intros d articles.', 'APP: Agree + Promise + Preview. Intros articles', 'content', 'best_practice', 0.82, 'copy_elite', 'system'),
('COPY_ELITE: Le curiosity gap technique: reveler 80% de l info dans le hook, forcer le clic pour les 20% restants. "Ce restaurant a triple son CA avec..." ', 'Curiosity gap: 80% info hook, 20% dans contenu. Forcer le clic', 'content', 'best_practice', 0.85, 'copy_elite', 'system'),
('COPY_ELITE: Le bucket brigade: mots de transition qui gardent le lecteur (Mais voila le truc... Et ce n est pas tout... Le meilleur?...). +30% temps de lecture.', 'Bucket brigade: mots transition (Mais voila... Et ce n est pas tout...) +30% lecture', 'content', 'best_practice', 0.82, 'copy_elite', 'system'),
('COPY_ELITE: Le power word injection: remplacer les mots faibles par des power words. "Bon" → "Extraordinaire". "Ameliorer" → "Transformer". "Important" → "Critique".', 'Power words: bon→extraordinaire, ameliorer→transformer, important→critique', 'content', 'best_practice', 0.82, 'copy_elite', 'system'),
('COPY_ELITE: Le headline score formula: specifique (chiffre) + benefice (resultat) + urgence (temporalite) + curiosite (surprise). Score 3/4 = bon. 4/4 = excellent.', 'Headline score: specifique + benefice + urgence + curiosite. 4/4 = excellent', 'content', 'best_practice', 0.85, 'copy_elite', 'system'),
('COPY_ELITE: Le email subject formula gagnante: [Prenom], [chiffre] [benefice] pour [cible] (ex: Marie, 3 astuces pour doubler vos reservations).', 'Subject email: Prenom + chiffre + benefice + cible', 'email', 'best_practice', 0.85, 'copy_elite', 'system'),
('COPY_ELITE: Le CTA microcopy: ajouter un texte rassurant sous le bouton (Pas de carte requise, Annulation en 1 clic, Resultat en 60s). +15% clics.', 'CTA microcopy rassurant sous bouton = +15% clics', 'content', 'best_practice', 0.85, 'copy_elite', 'system'),
('COPY_ELITE: Le storytelling STAR: Situation (contexte) → Tache (defi) → Action (ce qui a ete fait) → Resultat (chiffres). Pour les temoignages et case studies.', 'STAR storytelling: Situation + Tache + Action + Resultat. Temoignages', 'content', 'best_practice', 0.85, 'copy_elite', 'system'),
('COPY_ELITE: Le inverted pyramid writing: conclusion d abord, details ensuite. Le lecteur occupe obtient la valeur immediatement meme s il ne lit pas tout.', 'Inverted pyramid: conclusion d abord, details ensuite. Valeur immediate', 'content', 'best_practice', 0.85, 'copy_elite', 'system'),
-- B70-75: Cross-domain expertise partagee (200)
('CROSS_ELITE: Le prospect scoring universal: email ouvert=1pt, clic=3pt, site visite=5pt, pricing page=10pt, DM repondu=15pt, demo request=20pt, achat=100pt.', 'Scoring universel: email 1, clic 3, site 5, pricing 10, DM 15, demo 20, achat 100', NULL, 'best_practice', 0.88, 'cross_elite', 'system'),
('CROSS_ELITE: Le attribution multi-touch: 1st touch (decouverte) + last touch (conversion) + linear (repartition egale). Utiliser les 3 pour comprendre le funnel.', 'Attribution 3 modeles: 1st touch + last touch + linear. Utiliser les 3', NULL, 'best_practice', 0.82, 'cross_elite', 'system'),
('CROSS_ELITE: Le campaign synchronization: quand un email est envoye, le DM est programme 2h apres, et l ad retarget est active. Multi-canal synchrone = 3x impact.', 'Campaign sync: email → DM 2h apres → ad retarget. Multi-canal = 3x', NULL, 'best_practice', 0.85, 'cross_elite', 'system'),
('CROSS_ELITE: Le customer data platform (CDP): centraliser toutes les donnees client (CRM + email + analytics + social + support) = vue 360° + personnalisation.', 'CDP: centraliser CRM+email+analytics+social+support = vue 360°', NULL, 'best_practice', 0.82, 'cross_elite', 'system'),
('CROSS_ELITE: Le revenue waterfall analysis: new MRR + expansion - contraction - churn = net new MRR. Si net < 0, le business shrink malgre les nouveaux clients.', 'Revenue waterfall: new + expansion - contraction - churn. Si net < 0 = shrink', NULL, 'insight', 0.85, 'cross_elite', 'system'),
('CROSS_ELITE: Le growth accounting: sustainable growth = (organic + referral) / total growth. Si > 60% = durable. Si < 30% = dependant du paid.', 'Growth accounting: (organic+referral)/total. >60% durable, <30% paid-dependent', NULL, 'insight', 0.82, 'cross_elite', 'system'),
('CROSS_ELITE: Le content → lead → customer pipeline: 100 articles SEO → 1000 visiteurs/mois → 50 leads (5% CVR) → 5 clients (10% close) → 5 × LTV revenu.', 'Pipeline: 100 articles → 1000 visiteurs → 50 leads → 5 clients', NULL, 'insight', 0.82, 'cross_elite', 'system'),
('CROSS_ELITE: Le agent coordination timing: matin=prospection (DM+email), midi=contenu (publication), apres-midi=suivi (relances+commercial), soir=analyse (CEO+retention).', 'Agent timing: matin prospection, midi contenu, PM suivi, soir analyse', 'ceo', 'best_practice', 0.85, 'cross_elite', 'system'),
('CROSS_ELITE: Le feedback loop client → produit: chaque retour client (support, NPS, churn interview) alimente le backlog produit. Le client guide l evolution.', 'Feedback loop: retour client → backlog produit. Client guide evolution', NULL, 'best_practice', 0.85, 'cross_elite', 'system'),
('CROSS_ELITE: Le competitive intelligence matrix: pour chaque concurrent, tracker: pricing, features, positioning, content strategy, ad spend, reviews, growth.', 'Competitive matrix: pricing+features+positioning+content+ads+reviews+growth', 'ceo', 'best_practice', 0.82, 'cross_elite', 'system'),
('SECTOR_DEEP_REST: Le menu engineering avance: placer les plats les plus rentables en haut a droite du menu (eye-scanning pattern). +15% ventes plats cibles.', 'Menu engineering: plats rentables haut-droite = +15% ventes cibles', NULL, 'insight', 0.80, 'sector_deep', 'system'),
('SECTOR_DEEP_REST: Le Google reservation link: ajouter un lien de reservation direct sur la fiche Google genere 25% de reservations en plus.', 'GMaps reservation link restaurant = +25% reservations', 'gmaps', 'best_practice', 0.82, 'sector_deep', 'system'),
('SECTOR_DEEP_REST: Le Instagram food photography: lumiere naturelle + angle 45° + garnish visible + fond neutre = photo qui donne faim et fait scroller.', 'Food photo: lumiere naturelle + 45° + garnish + fond neutre = engagement', 'content', 'best_practice', 0.82, 'sector_deep', 'system'),
('SECTOR_DEEP_BOUT: Le vitrine digitale: photos de la vitrine en stories quotidiennes + nouveautes hebdo + behind-the-scenes = trafic en boutique +20%.', 'Vitrine digitale stories boutique = +20% trafic boutique', 'content', 'insight', 0.80, 'sector_deep', 'system'),
('SECTOR_DEEP_BOUT: Le click & collect local: proposer la reservation en ligne + retrait en boutique augmente les ventes de 15% et le panier moyen de 25%.', 'Click & collect local boutique = +15% ventes +25% panier', NULL, 'insight', 0.80, 'sector_deep', 'system'),
('SECTOR_DEEP_COACH: Le authority building coach: 1 article/semaine + 1 podcast/mois + 1 webinaire/trimestre = expert reconnu en 6 mois.', 'Coach authority: 1 article/sem + 1 podcast/mois + 1 webinaire/trim = expert 6 mois', NULL, 'best_practice', 0.82, 'sector_deep', 'system'),
('SECTOR_DEEP_COIF: Le booking en ligne coiffeur: les salons avec prise de RDV en ligne (Treatwell, Planity) ont 30% plus de RDV que ceux par telephone.', 'Booking online coiffeur = +30% RDV vs telephone', NULL, 'insight', 0.82, 'sector_deep', 'system'),
('SECTOR_DEEP_COIF: Le before/after coiffure: poster un avant/apres de chaque coupe sur IG = contenu illimite + social proof + engagement 5x.', 'Before/after coiffure IG = contenu illimite + 5x engagement', 'content', 'insight', 0.82, 'sector_deep', 'system'),
('SECTOR_DEEP_FLEUR: Le abonnement floral hebdomadaire: les fleuristes qui proposent un abo (bouquet/semaine) ont 60% de retention et un revenu previsible.', 'Abo floral hebdo = 60% retention + revenu previsible', NULL, 'insight', 0.78, 'sector_deep', 'system'),
('SECTOR_DEEP_FLEUR: Le seasonal marketing fleuriste: anticiper les pics (Saint-Valentin, Fete des meres, Toussaint) 4 semaines avant avec du contenu + promo.', 'Fleuriste seasonal: anticiper pics 4 semaines avec contenu + promo', NULL, 'best_practice', 0.80, 'sector_deep', 'system'),
('MASTER_AGENT_CONTENT: Le content agent doit maintenir un calendrier de 4 semaines a l avance, adapter chaque post au ton de la marque client, et varier les formats (Reel, carrousel, texte, story).', 'Agent content: calendrier 4 sem + ton marque + varier formats', 'content', 'best_practice', 0.92, 'master_agent', 'system'),
('MASTER_AGENT_CONTENT: Le content agent analyse les meilleurs posts (top 10% engagement) et reproduit les patterns gagnants: meme structure de hook, meme format, meme timing.', 'Agent content: analyser top 10% posts → reproduire patterns gagnants', 'content', 'best_practice', 0.90, 'master_agent', 'system'),
('MASTER_AGENT_EMAIL: L agent email doit maintenir un sender score > 80, respecter le quota Brevo (300/jour), varier les templates, et analyser chaque campagne (OR, CTR, replies).', 'Agent email: sender score >80 + quota 300 + varier templates + analyser', 'email', 'best_practice', 0.92, 'master_agent', 'system'),
('MASTER_AGENT_EMAIL: L agent email segmente par temperature (cold=education, warm=social proof, hot=offre directe) et par etape sequence (1=intro, 2=valeur, 3=CTA, 4=FOMO, 5=dernier rappel).', 'Agent email: segmenter temperature × etape sequence', 'email', 'best_practice', 0.90, 'master_agent', 'system'),
('MASTER_AGENT_COMMERCIAL: L agent commercial enrichit chaque prospect (email valide, type commerce, IG, Google rating) et score automatiquement (0-20) selon la qualite du fit.', 'Agent commercial: enrichir + scorer 0-20 chaque prospect', 'commercial', 'best_practice', 0.90, 'master_agent', 'system'),
('MASTER_AGENT_COMMERCIAL: L agent commercial detecte les prospects HOT (score>15, temperature hot, repondu ou demo) et les remonte au CEO pour action prioritaire.', 'Agent commercial: detecter HOT score>15 → remonter CEO priorite', 'commercial', 'best_practice', 0.90, 'master_agent', 'system'),
('MASTER_AGENT_SEO: L agent SEO analyse les keywords concurrents, identifie les gaps de contenu, et genere des articles optimises (1500+ mots, H2/H3, images, schema markup).', 'Agent SEO: keywords concurrents + gaps + articles optimises 1500+ mots', 'seo', 'best_practice', 0.88, 'master_agent', 'system'),
('MASTER_AGENT_ADS: L agent ads teste 3-5 creatives/semaine, coupe les perdantes en 48h, scale les gagnantes +20%/jour, et respecte le budget ROAS cible.', 'Agent ads: 3-5 creatives/sem + couper 48h + scale +20% + ROAS cible', 'ads', 'best_practice', 0.88, 'master_agent', 'system'),
('MASTER_AGENT_DM: L agent DM prepare des messages ultra-personnalises (mention post recent, compliment specifique, question ouverte) et ne depasse jamais 30 DMs/jour pour eviter les sanctions IG.', 'Agent DM: ultra-personnalise + max 30/jour + mention post recent', 'dm_instagram', 'best_practice', 0.90, 'master_agent', 'system'),
('MASTER_AGENT_WHATSAPP: L agent WhatsApp respecte la fenetre 24h, segmente les broadcasts, ne depasse jamais 2 promos/semaine, et propose toujours l opt-out.', 'Agent WhatsApp: fenetre 24h + segment + max 2 promos/sem + opt-out', 'whatsapp', 'best_practice', 0.90, 'master_agent', 'system'),
('MASTER_AGENT_CHATBOT: L agent chatbot repond en < 3 secondes, propose des boutons de reponse rapide, escalade a un humain apres 3 questions sans resolution, et collecte le feedback (pouce haut/bas).', 'Agent chatbot: <3s + boutons rapides + escalade 3 questions + feedback', 'chatbot', 'best_practice', 0.88, 'master_agent', 'system'),
('MASTER_AGENT_GMAPS: L agent GMaps poste 1 Google Post/semaine, repond a chaque avis < 24h, et maintient la fiche a jour (horaires, photos, services, Q&A).', 'Agent GMaps: 1 post/sem + repondre avis <24h + fiche a jour', 'gmaps', 'best_practice', 0.88, 'master_agent', 'system'),
('MASTER_AGENT_RETENTION: L agent retention surveille le health score de chaque client, detecte les signaux de pre-churn (usage baisse, tickets, inactivite), et declenche des actions de save.', 'Agent retention: health score + detecter pre-churn + actions save', 'retention', 'best_practice', 0.90, 'master_agent', 'system'),
('MASTER_AGENT_ONBOARDING: L agent onboarding guide chaque nouveau client vers son aha moment en < 5 min, envoie des emails lifecycle (J0, J1, J3, J7, J14), et mesure le taux d activation.', 'Agent onboarding: aha <5min + emails lifecycle + mesurer activation', 'onboarding', 'best_practice', 0.90, 'master_agent', 'system'),
('MASTER_AGENT_CEO: Le CEO coordonne tous les agents, redistribue les insights (trend → contenu, prospect HOT → commercial), alerte le client sur les metriques critiques, et optimise les budgets.', 'CEO: coordonner agents + redistribuer insights + alerter + optimiser budgets', 'ceo', 'best_practice', 0.92, 'master_agent', 'system'),
('MASTER_AGENT_COMPTABLE: L agent comptable surveille le MRR, le churn, le LTV/CAC, le runway, et alerte si un KPI passe en zone rouge. Rapport financier mensuel automatique.', 'Agent comptable: MRR+churn+LTV/CAC+runway. Alerte rouge. Rapport mensuel', 'comptable', 'best_practice', 0.88, 'master_agent', 'system'),
('MASTER_AGENT_RH: L agent RH surveille la satisfaction equipe, les performances individuelles, le turnover risk, et recommande des actions (formation, augmentation, recrutement).', 'Agent RH: satisfaction + performances + turnover risk + recommandations', 'rh', 'best_practice', 0.85, 'master_agent', 'system'),
('MASTER_AGENT_MARKETING: L agent marketing analyse les performances cross-canal, identifie les canaux les plus rentables, et recommande la reallocation budgetaire.', 'Agent marketing: analyse cross-canal + canaux rentables + reallocation', 'marketing', 'best_practice', 0.88, 'master_agent', 'system'),
('MASTER_AGENT_TIKTOK: L agent TikTok detecte les trending sounds/formats dans les 24h, propose des concepts adaptes a la marque, et analyse les metriques (completion, shares, follows).', 'Agent TikTok: trends 24h + concepts marque + analyser completion/shares/follows', 'tiktok_comments', 'best_practice', 0.85, 'master_agent', 'system')
